        const float ng_val = normal_grad_v.x;
        const float raw_dir = (sg_val - ng_val) * inv_norm;
        const float old_ema_dir = v_dir_ema_val_x;
        const float new_ema_dir = ema_decay * old_ema_dir + (1.0f - ema_decay) * raw_dir;
        v_dir_ema_val_x = new_ema_dir;
        p.x = new_ema_dir;
    }
    // Component y
    {
        const float sg_val = sam_grad_v.y;
        const float ng_val = normal_grad_v.y;
        const float raw_dir = (sg_val - ng_val) * inv_norm;
        const float old_ema_dir = v_dir_ema_val_y;
        const float new_ema_dir = ema_decay * old_ema_dir + (1.0f - ema_decay) * raw_dir;
        v_dir_ema_val_y = new_ema_dir;
        p.y = new_ema_dir;
    }
    // Component z
    {
        const float sg_val = sam_grad_v.z;
        const float ng_val = normal_grad_v.z;
        const float raw_dir = (sg_val - ng_val) * inv_norm;
        const float old_ema_dir = v_dir_ema_val_z;
        const float new_ema_dir = ema_decay * old_ema_dir + (1.0f - ema_decay) * raw_dir;
        v_dir_ema_val_z = new_ema_dir;
        p.z = new_ema_dir;
    }
    // Component w
    {
        const float sg_val = sam_grad_v.w;
        const float ng_val = normal_grad_v.w;
        const float raw_dir = (sg_val - ng_val) * inv_norm;
        const float old_ema_dir = v_dir_ema_val_w;
        const float new_ema_dir = ema_decay * old_ema_dir + (1.0f - ema_decay) * raw_dir;
        v_dir_ema_val_w = new_ema_dir;
        p.w = new_ema_dir;
    }
}

void launch_looksam_direction_step_moe_q4_vec4(
    torch::Tensor param,
    torch::Tensor grad,
    torch::Tensor v_dir_ema_q,
    torch::Tensor sam_grad,
    torch::Tensor normal_grad,
    torch::Tensor active_mask,
    float ema_decay,
    float inv_norm,
    int global_step
) {
    const int N = param.numel();
    if (N == 0) return;

    const int N4 = N / 4;
    const int grid = (N4 + 256 - 1) / 256;
    looksam_direction_step_moe_q4_vec4_kernel<<<grid, 256>>>(
        reinterpret_cast<float4*>(param.data_ptr<float>()),
        reinterpret_cast<const float4*>(grad.data_ptr<float>()),
        reinterpret_cast<__nv_bfloat16*>(v_dir_ema_q.data_ptr()),
        reinterpret_cast<const float4*>(sam_grad.data_ptr<float>()),
        reinterpret_cast<const float4*>(normal_grad.data_ptr<float>()),
        active_mask.data_ptr<bool>(),
        ema_decay,
        inv_norm,
        static_cast<unsigned>(global_step),
        N4);
}


